/*! 
 * NextGen Solutions Client Script
 * Optimally deferred, Cloudflare Rocket Loader compatible.
 */
document.addEventListener('DOMContentLoaded', () => {
    // Determine active navigation state securely
    const currentPath = window.location.pathname;
    const navLinks = document.querySelectorAll('.nav-links a');
    
    navLinks.forEach(link => {
        // Strip out domain to compare relative paths
        const linkPath = new URL(link.href).pathname;
        if(linkPath === currentPath) {
            link.classList.add('active');
            link.setAttribute('aria-current', 'page');
        } else {
            link.classList.remove('active');
            link.removeAttribute('aria-current');
        }
    });

    // Contact Form Logic (Simulation for static site demo)
    const contactForm = document.getElementById('contactForm');
    if (contactForm) {
        contactForm.addEventListener('submit', (e) => {
            e.preventDefault(); // Prevent actual submission for demo
            
            const submitBtn = contactForm.querySelector('button[type="submit"]');
            const originalText = submitBtn.textContent;
            
            submitBtn.disabled = true;
            submitBtn.textContent = 'Sending securely...';
            
            setTimeout(() => {
                alert('Thank you! Your message was sent securely.');
                contactForm.reset();
                submitBtn.disabled = false;
                submitBtn.textContent = originalText;
            }, 800);
        });
    }
});
